v_boolean   boolean;
V_Psycho		number;
V_DEDUCT    VARCHAR2(51);
my_text2  	VARCHAR2(5100);
V_PROCUCT_CODE NUMBER;


Cursor cur_award_prompt Is
 SELECT A.AWARD_TYPE_FLAG
