                                              I_Dec_Incr_Seq_No,
                                              I_Dec_Doc_Type,
                                              0,0,'00001','01825','01841');-- ΗΛΙΚΙΑ ΣΥΝΤΑΞΙΟΔΟΤΗΣΗΣ

   -- CHRYS 7/9/2023 :CP_HLIKIA_AITHSHS := P_RETIREMENT_AGE;
