      function cf_age_reduction2Formula return Number 
is
-- CHRYS 24/1/2023
V_NUMBER		NUMBER;
  /*
  cursor c1
  is
    /*select distinct
       		 nvl(a.age_reduction,0) age_reduction
  	  from pen_calc_adapod_results_eteaep a
  	 where a.ins_insured_id = :P_INSURED_ID;*/
  	 
  	/* CHRYS 24/1/2023
  	 SELECT NVL(REDUCTION_AMOUNT,0) age_reduction
  	 FROM PEN_ETEAEP_AGE_REDUCTION
  	 WHERE ACCOUNT_NO= :P_ACC_ACCOUNT_NO;
  	END CHRYS 24/1/2023 */
  
  CURSOR 	C1 IS
  SELECT 	DISTINCT AGE_REDUCTION
  FROM 		PEN_CALC_ADAPOD_RESULTS_ETEAEP A
  WHERE 	ACCOUNT_NO= :P_ACC_ACCOUNT_NO
  AND 		YEAR < 2015
  ORDER BY AGE_REDUCTION DESC;
  
  
  	
  v_res number;
  
begin
  	
    open C1;
    fetch C1 
    into V_NUMBER;
    close C1;
   	
  PENBAT_DEBUGING('P_ACC_ACCOUNT_NO = '||:P_ACC_ACCOUNT_NO, 'CHRYS_24012023');
  PENBAT_DEBUGING('V_NUMBER = '||V_NUMBER, 'CHRYS_24012023');
  PENBAT_DEBUGING('cs_incr_amount = '||:cs_incr_amount, 'CHRYS_24012023');
  PENBAT_DEBUGING('cs_amount_a = '||:cs_amount_a, 'CHRYS_24012023');
  

  
   
   -- CHRYS 24/1/2023 v_res := nvl(V_NUMBER,0)*(nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0))/100 ;
   v_res := nvl(V_NUMBER,0)*(nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0)) ; -- CHRYS 24/1/2023
   return v_res;
   
end;

      function cf_amount_b_dataFormula return Number 
is
  cursor c1
  is
    select distinct
		       a.ranta,
		       a.total_contributions_amt_b contr_amount
		  from pen_calc_adapod_results_eteaep a
		 where a.account_no  = :P_ACC_ACCOUNT_NO -- CHRYS 13/8/2018 :P_INSURED_ID
		   and nvl(a.total_contributions_amt_b,0) <> 0;
  
  v_contr_amount number;
  
begin
   open c1;
   fetch c1 into :cp_ranta,v_contr_amount;
   close c1;
   
   return v_contr_amount;
   
end;

      function cf_amount_bFormula return Number 
is

-- CHRYS 4/7/2022

CURSOR CUR_AMOUNT_B IS
SELECT DISTINCT AMOUNT_B
FROM	PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND		NVL(AMOUNT_B,0) != 0;

-- END CHRYS 4/7/2022

  cursor c1
  is
    select distinct
           round(a.total_contributions_amt_b/(a.ranta * 12),2) poso_b
      from pen_calc_adapod_results_eteaep a
     where a.account_no  = :P_ACC_ACCOUNT_NO -- CHRYS 28/8/2018 :P_INSURED_ID
       and nvl(a.total_contributions_amt_b,0) <> 0;
  
  v_amount_b number;
  
begin
   open c1;
   fetch c1 into v_amount_b;
   close c1;
   
	IF V_AMOUNT_B != 0 THEN
		RETURN V_AMOUNT_B;
	ELSE
		OPEN	CUR_AMOUNT_B;
		FETCH	CUR_AMOUNT_B
		INTO V_AMOUNT_B;
		CLOSE CUR_AMOUNT_B;	
   	RETURN V_AMOUNT_B;
  END IF;
   
end;

      function cf_amount_a_bFormula return Number is

V_AMOUNT NUMBER;
begin
V_AMOUNT :=  nvl(:cf_final_amount_a,0) + nvl(:cf_amount_b,0);
--COMBAT_dEBUGING(':cf_amount_b = '||:cf_amount_b, 'CHRYS_1303');  
--COMBAT_dEBUGING('V_AMOUNT = '||V_AMOUNT, 'CHRYS_1303');  
   return V_AMOUNT;
end;

      function cf_final_amount_aFormula return Number is

-- CHRYS 4/7/2022
V_AMOUNT_A	NUMBER; 

CURSOR 	CUR_AMOUNT_A IS
SELECT 	DISTINCT ADAPODOTIKH_AMT
FROM		PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE 	ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND			NVL(ADAPODOTIKH_AMT,0) != 0;
-- END CHRYS 4/7/2022

begin
	 -- CHRYS 4/7/2022 return nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0) - nvl(:cf_age_reduction,0)- nvl(:cf_disabil_reduction,0);-- chrys 14/2/2019
	V_AMOUNT_A := nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0) - nvl(:cf_age_reduction,0)- nvl(:cf_disabil_reduction,0); -- CHRYS 4/7/2022 
  V_AMOUNT_A := V_AMOUNT_A + NVL(:CS_ADAP_0075,0); -- CHRYS 27/11/2023
	IF V_AMOUNT_A != 0 THEN
		RETURN V_AMOUNT_A;
	ELSE
		OPEN	CUR_AMOUNT_A;
		FETCH	CUR_AMOUNT_A
		INTO V_AMOUNT_A;
		CLOSE CUR_AMOUNT_A;	
		
		V_AMOUNT_A := V_AMOUNT_A + NVL(:CS_ADAP_0075,0); -- CHRYS 27/11/2023
   	RETURN V_AMOUNT_A;
  END IF;
end;

      function CF_DISABIL_REDUCTIONFormula return Number is

/*CURSOR CUR_DISABIL_REDUCTION IS
SELECT DISTINCT DISABIL_PENSION_REDUCTION
FROM PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO;
*/
V_NUMBER			NUMBER;
V_REDUCTION		NUMBER;

/*OPEN CUR_DISABIL_REDUCTION;
FETCH CUR_DISABIL_REDUCTION
INTO V_NUMBER;
CLOSE CUR_DISABIL_REDUCTION;

v_reduction := nvl(V_NUMBER,0)*(nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0))/100 ;
*/
v_calc_begin_date_varchar varchar2(10);

begin
  v_calc_begin_date_varchar := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
			 0,:p_form_id,'00001','00035','00200');
IF v_calc_begin_date_varchar IS NOT NULL THEN
   v_NUMBER := 100-TO_NUMBER(v_calc_begin_date_varchar);
END IF;

v_reduction := nvl(V_NUMBER,0)*(nvl(:cs_amount_a,0) + nvl(:cs_incr_amount,0))/100 ;

RETURN V_REDUCTION;

end;

