      function CF_MIN_DATE_POSO_A1Formula return DATE is

CURSOR CUR_MIN_DATE IS
SELECT MIN(TO_DATE((TO_CHAR(MONTH)||'/'||TO_CHAR(YEAR)), 'MM/RRRR'))
       --LAST_DAY(MAX(TO_DATE((TO_CHAR(MONTH)||'/'||TO_CHAR(YEAR)), 'MM/RRRR')))
FROM    pen_calc_adapod_results_eteaep A
WHERE a.ACCOUNT_NO         = :P_ACC_ACCOUNT_NO--1542500
and nvl(a.v_percent_ksb,0)   = 0
and nvl(a.average_income,0) <> 0;

V_MIN_DATE DATE;
begin
  
  OPEN CUR_MIN_DATE;
  FETCH CUR_MIN_DATE
  INTO V_MIN_DATE;
  CLOSE CUR_MIN_DATE;
  
  RETURN V_MIN_DATE;
  
end;

      function CF_MAX_DATE_POSO_A1Formula return Date is


CURSOR CUR_MIN_DATE IS
SELECT LAST_DAY(MAX(TO_DATE((TO_CHAR(MONTH)||'/'||TO_CHAR(YEAR)), 'MM/RRRR')))
FROM    pen_calc_adapod_results_eteaep A
WHERE a.ACCOUNT_NO         = :P_ACC_ACCOUNT_NO--1542500
and nvl(a.v_percent_ksb,0)   = 0
and nvl(a.average_income,0) <> 0;

V_MAX_DATE DATE;
begin
  
  OPEN CUR_MIN_DATE;
  FETCH CUR_MIN_DATE
  INTO V_MAX_DATE;
  CLOSE CUR_MIN_DATE;
  
  RETURN V_MAX_DATE;
  
end;

