      function CF_ANALOG_ISODYNAMO_ETHSIOForm return Number is

CURSOR C1 IS
SELECT DISTINCT ROUND (AVERAGE_INCOME * 0.45 * 12/100 ,2)  AMOUNT_A_ETHSIO,
			 ROUND (AVERAGE_INCOME * 0.06 * 12 ,2)  AMOUNT_B_ETHSIO
FROM   PEN_CALC_ADAPOD_RESULTS_ETEAEP  A
WHERE  A.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND    A.STATUS = '1'
AND		 NVL(A.V_PERCENT_KSB,0) = 0
AND		 NVL(A.AVERAGE_INCOME,0) != 0
 
;

V_C1 NUMBER;
V_C2 NUMBER;



begin
	OPEN C1;
	FETCH C1
	INTO V_C1,
			 V_C2;
	CLOSE C1;
	
	
	RETURN ROUND(V_C1 * :V_SAI1 + V_C2 * :V_SAI3,2);
	EXCEPTION WHEN OTHERS THEN RETURN 0;
  
end;

