      function CF_TOTAL_YEARSFormula return Number is
-- CHRYS 10/10/2023
CURSOR  CUR_TOTAL_YEARS_A IS
SELECT  DISTINCT TOTAL_YEARS
FROM    PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE   ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     YEAR <= 2014;

V_TOTAL_YEARS_A     NUMBER;

CURSOR  CUR_TOTAL_YEARS_B IS
SELECT  DISTINCT TOTAL_YEARS
FROM    PEN_CALC_ADAPOD_RESULTS_ETEAEP
WHERE   ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND     YEAR >= 2015;

V_TOTAL_YEARS_B     NUMBER;
V_TOTAL_YEARS       NUMBER;
-- END CHRYS 10/10/2023

BEGIN
	
	-- CHRYS 10/10/2023
OPEN    CUR_TOTAL_YEARS_A;
FETCH   CUR_TOTAL_YEARS_A
INTO    V_TOTAL_YEARS_A;
CLOSE   CUR_TOTAL_YEARS_A;

OPEN    CUR_TOTAL_YEARS_B;
FETCH   CUR_TOTAL_YEARS_B
INTO    V_TOTAL_YEARS_B;
CLOSE   CUR_TOTAL_YEARS_B;

--SRW.MESSAGE(100,'V_TOTAL_YEARS_A :' ||V_TOTAL_YEARS_A);
--SRW.MESSAGE(100,'V_TOTAL_YEARS_A :' ||V_TOTAL_YEARS_B);

--SRW.MESSAGE(100,'V_TOTAL_YEARS TOTAL :' ||(NVL(V_TOTAL_YEARS_A,0) + NVL(V_TOTAL_YEARS_B,0)));

V_TOTAL_YEARS := ROUND( (NVL(V_TOTAL_YEARS_A,0) + NVL(V_TOTAL_YEARS_B,0)),2);

-- END CHRYS 10/10/2023

RETURN (V_TOTAL_YEARS);
END;

